module RefModule(
    input clk,
    input rst,
    input we,
    input [2:0] ra1,
    input [2:0] ra2,
    input [2:0] wa,
    input [31:0] wd,

    output reg [31:0] rd1,
    output reg [31:0] rd2
);

reg [31:0] unused_regs[7:0];

always@(posedge clk or posedge rst)
begin
    if(rst)
    begin
        unused_regs[0] <= 0;
        unused_regs[1] <= 0;
        unused_regs[2] <= 0;
        unused_regs[3] <= 0;
        unused_regs[4] <= 0;
        unused_regs[5] <= 0;
        unused_regs[6] <= 0;
        unused_regs[7] <= 0;
    end
    else if(we)
        unused_regs[wa] <= wd;
end

always@(*)
begin
    rd1 = unused_regs[ra1];
    rd2 = unused_regs[ra2];
end

endmodule
